// Event factory. make(type, payload) returns { type, payload } and validates
// that type is a non-empty string and payload is a non-null object.
function make(type, payload) {
  if (typeof type !== "string" || type.length === 0) {
    throw new Error(`invalid event type: ${type}`);
  }
  if (typeof payload !== "object" || payload === null) {
    throw new Error(`invalid event payload: ${payload}`);
  }
  return { type, payload };
}
module.exports = { make };
